  Objective: Implement the core grid data structure (matrix) and cell occupancy management for blocks and gems
  Result: ```python
class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[None for _ in range(width)] for _ in range(height)]

    def is_valid_position(self, x, y):
        """Check if a given position is within the grid boundaries."""
        return 0 <= x < self.width and 0 <= y < self.height

    def is_cell_occupied(self, x, y):
        """Check if a given cell is occupied by a block or gem."""
        if not self.is_valid_position(x, y):
            return True  # Treat out-of-bounds as occupied
        return self.grid[y][x] is not None

    def place_block(self, x, y, block):
        """Place a block or gem at a given position."""
        if self.is_valid_position(x, y):
            self.grid[y][x] = block
        else:
            raise ValueError("Invalid position for placing block.")

    def remove_block(self, x, y):
        """Remove a block or gem from a given position."""
        if self.is_valid_position(x, y):
            self.grid[y][x] = None
        else:
            raise ValueError("Invalid position for removing block.")

    def get_cell_value(self, x, y):
          """Get the value of a cell at the specified coordinates."""
          if self.is_valid_position(x,y):
            return self.grid[y][x]
          else:
            return None

    def print_grid(self):
        """Print the grid for debugging purposes."""
        for row in self.grid:
            print(row)

    def clear_grid(self):
        """Clear all blocks/gems from the grid."""
        self.grid = [[None for _ in range(self.width)] for _ in range(self.height)]
